  1	import * as React from 'react';
  2	import {
  3	  IBM_SCALE_NAMESPACE,
  4	  IBM_SCALE_OPERATOR_NAME,
  5	} from '@odf/core/constants';
  6	import { RemoteClusterKind } from '@odf/core/types/scale';
  7	import {
  8	  ClusterServiceVersionKind,
  9	  ClusterServiceVersionModel,
 10	  getName,
 11	  useCustomTranslation,
 12	} from '@odf/shared';
 13	import HealthItem from '@odf/shared/dashboards/status-card/HealthItem';
 14	import { RemoteClusterModel } from '@odf/shared/models/scale';
 15	import { getOperatorHealthState, referenceForModel } from '@odf/shared/utils';
 16	import {
 17	  HealthState,
 18	  useK8sWatchResource,
 19	} from '@openshift-console/dynamic-plugin-sdk';
 20	import {
 21	  Card,
 22	  CardBody,
 23	  CardHeader,
 24	  CardTitle,
 25	  Gallery,
 26	  GalleryItem,
 27	} from '@patternfly/react-core';
 28	
 29	const getRemoteClusterConnectionHealth = (
 30	  remoteCluster: RemoteClusterKind,
 31	  loading: boolean,
 32	  loadError: any
 33	) => {
 34	  if (loading) {
 35	    return HealthState.LOADING;
 36	  }
 37	  if (loadError) {
 38	    return HealthState.ERROR;
 39	  }
 40	  if (!remoteCluster) {
 41	    return HealthState.NOT_AVAILABLE;
 42	  }
 43	  const remoteClusterConnectionStatus = remoteCluster?.status?.conditions?.find(
 44	    (condition) => condition.type === 'Available'
 45	  )?.status;
 46	  return remoteClusterConnectionStatus === 'True'
 47	    ? HealthState.OK
 48	    : HealthState.ERROR;
 49	};
 50	
 51	const StatusCard: React.FC<{}> = () => {
 52	  const { t } = useCustomTranslation();
 53	  const [csvs, csvsLoaded, csvsLoadError] = useK8sWatchResource<
 54	    ClusterServiceVersionKind[]
 55	  >({
 56	    kind: referenceForModel(ClusterServiceVersionModel),
 57	    namespaced: true,
 58	    isList: true,
 59	    namespace: IBM_SCALE_NAMESPACE,
 60	  });
 61	
 62	  const [remoteClusters, remoteClustersLoaded, remoteClustersLoadError] =
 63	    useK8sWatchResource<RemoteClusterKind[]>({
 64	      kind: referenceForModel(RemoteClusterModel),
 65	      isList: true,
 66	      namespace: IBM_SCALE_NAMESPACE,
 67	    });
 68	
 69	  const ibmCSV = csvs?.find((csv) =>
 70	    getName(csv).includes(IBM_SCALE_OPERATOR_NAME)
 71	  );
 72	  const flashOperator = getOperatorHealthState(
 73	    ibmCSV?.status?.phase,
 74	    !csvsLoaded,
 75	    csvsLoadError
 76	  );
 77	
 78	  const remoteClusterConnectionHealth = getRemoteClusterConnectionHealth(
 79	    remoteClusters?.[0],
 80	    !remoteClustersLoaded,
 81	    remoteClustersLoadError
 82	  );
 83	
 84	  return (
 85	    <Card>
 86	      <CardHeader>
 87	        <CardTitle>{t('Status')}</CardTitle>
 88	      </CardHeader>
 89	      <CardBody>
 90	        <Gallery hasGutter>
 91	          <GalleryItem>
 92	            <HealthItem title={t('Operator')} state={flashOperator.state} />
 93	          </GalleryItem>
 94	          <GalleryItem>
 95	            <HealthItem
 96	              title={t('Connection')}
 97	              state={remoteClusterConnectionHealth}
 98	            />
 99	          </GalleryItem>
100	        </Gallery>
101	      </CardBody>
102	    </Card>
103	  );
104	};
105	
106	export default StatusCard;

